const { Client: ProjectClient } = require('magicbell-js/project-client');

const runId = process.env.ZEALT_RUN_ID;
const email = `REDACTED+${runId}@gmail.com`;

const client = new ProjectClient({
  token: process.env.MAGICBELL_PROJECT_TOKEN,
});

async function main() {
  try {
    console.log('Creating broadcast to email:', email);
    const response = await client.broadcasts.createBroadcast({
      title: 'Test Notification title',
      content: 'Test Notification content',
      recipients: [
        { email: email }
      ]
    });
    console.log('Broadcast response:', JSON.stringify(response.data, null, 2));
  } catch (error) {
    console.error('Error:', error);
  }
}

main();

